import React, { useState, useEffect } from "react";
import "./Internship.css";

export default function Internship() {
  const user = JSON.parse(localStorage.getItem("loggedInUser"));
  const [internships, setInternships] = useState(
    JSON.parse(localStorage.getItem("internships")) || []
  );

  const [formData, setFormData] = useState({
    title: "",
    company: "",
    description: "",
    link: "",
  });

  const handleAdd = () => {
    const updated = [...internships, formData];
    localStorage.setItem("internships", JSON.stringify(updated));
    setInternships(updated);
    setFormData({ title: "", company: "", description: "", link: "" });
  };

  const handleDelete = (index) => {
    const updated = internships.filter((_, i) => i !== index);
    localStorage.setItem("internships", JSON.stringify(updated));
    setInternships(updated);
  };

  const handleEdit = (index) => {
    setFormData(internships[index]);
    handleDelete(index);
  };

  const isStudent = user.role === "Student";
  const isHR = user.role === "HR";
  const isAdmin = user.role === "Admin";

  return (
    <div className="internship-container">
      <h2>Internship Opportunities</h2>

      {!isStudent && (
        <div className="form-section">
          <input
            type="text"
            placeholder="Title"
            value={formData.title}
            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
          />
          <input
            type="text"
            placeholder="Company"
            value={formData.company}
            onChange={(e) => setFormData({ ...formData, company: e.target.value })}
          />
          <textarea
            placeholder="Description"
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
          />
          <input
            type="text"
            placeholder="Apply Link"
            value={formData.link}
            onChange={(e) => setFormData({ ...formData, link: e.target.value })}
          />
          <button onClick={handleAdd}>Add Internship</button>
        </div>
      )}

      <div className="internship-list">
        {internships.length === 0 ? (
          <p>No internships available.</p>
        ) : (
          internships.map((item, index) => (
            <div key={index} className="internship-card">
              <h3>{item.title}</h3>
              <p><strong>Company:</strong> {item.company}</p>
              <p>{item.description}</p>
              <a href={item.link} target="_blank" rel="noreferrer">Apply</a>

              {isAdmin && (
                <div className="action-buttons">
                  <button onClick={() => handleEdit(index)}>Edit</button>
                  <button onClick={() => handleDelete(index)}>Delete</button>
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
